import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { Upload, FileText, AlertCircle, CheckCircle } from 'lucide-react';
import { apiService } from '../services/api';
import { getPolicyTypeDisplay } from '../utils/utils';
import toast from 'react-hot-toast';

const UploadPolicy = () => {
  const navigate = useNavigate();
  const [selectedFile, setSelectedFile] = useState(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [dragActive, setDragActive] = useState(false);

  const {
    register,
    handleSubmit,
    formState: { errors },
    watch,
  } = useForm();

  const handleFileSelect = (file) => {
    if (file) {
      const validTypes = ['application/pdf', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
      if (!validTypes.includes(file.type)) {
        toast.error('Please select a PDF or DOCX file');
        return;
      }

      if (file.size > 10 * 1024 * 1024) { // 10MB
        toast.error('File size must be less than 10MB');
        return;
      }

      setSelectedFile(file);
    }
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFileSelect(e.dataTransfer.files[0]);
    }
  };

  const onSubmit = async (data) => {
    if (!selectedFile) {
      toast.error('Please select a file to upload');
      return;
    }

    setIsUploading(true);
    setUploadProgress(0);

    try {
      const formData = new FormData();
      formData.append('policyFile', selectedFile);

      // Add all form fields
      Object.keys(data).forEach(key => {
        if (data[key]) {
          formData.append(key, data[key]);
        }
      });

      // Simulate progress (in real app, this would come from the upload)
      const progressInterval = setInterval(() => {
        setUploadProgress(prev => {
          if (prev >= 90) {
            clearInterval(progressInterval);
            return 90;
          }
          return prev + 10;
        });
      }, 200);

      const response = await apiService.policies.upload(formData);

      clearInterval(progressInterval);
      setUploadProgress(100);

      toast.success('Policy uploaded and analyzed successfully!');

      setTimeout(() => {
        navigate('/policies');
      }, 1500);

    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to upload policy');
      console.error('Upload error:', error);
    } finally {
      setIsUploading(false);
      setUploadProgress(0);
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900">Upload Policy</h1>
        <p className="mt-2 text-gray-600">Upload and analyze your insurance policy document</p>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-8">
        {/* File Upload */}
        <div className="card">
          <div className="card-body">
            <div className="mb-4">
              <h3 className="text-lg font-medium text-gray-900">Policy Document</h3>
              <p className="text-sm text-gray-500">Upload a PDF or DOCX file (max 10MB)</p>
            </div>

            <div
              className={`relative border-2 border-dashed rounded-lg p-8 text-center transition-colors ${
                dragActive
                  ? 'border-primary-500 bg-primary-50'
                  : selectedFile
                  ? 'border-success-500 bg-success-50'
                  : 'border-gray-300 hover:border-gray-400'
              }`}
              onDragEnter={handleDrag}
              onDragLeave={handleDrag}
              onDragOver={handleDrag}
              onDrop={handleDrop}
            >
              <input
                type="file"
                accept=".pdf,.docx"
                onChange={(e) => handleFileSelect(e.target.files[0])}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                disabled={isUploading}
              />

              <div className="flex flex-col items-center">
                {selectedFile ? (
                  <>
                    <CheckCircle className="h-12 w-12 text-success-500 mb-4" />
                    <div className="text-sm font-medium text-gray-900">
                      {selectedFile.name}
                    </div>
                    <div className="text-xs text-gray-500">
                      {(selectedFile.size / 1024 / 1024).toFixed(2)} MB
                    </div>
                    <button
                      type="button"
                      onClick={() => setSelectedFile(null)}
                      className="mt-2 text-sm text-danger-600 hover:text-danger-500"
                      disabled={isUploading}
                    >
                      Remove file
                    </button>
                  </>
                ) : (
                  <>
                    <Upload className="h-12 w-12 text-gray-400 mb-4" />
                    <div className="text-sm font-medium text-gray-900">
                      Drop your policy file here, or click to browse
                    </div>
                    <div className="text-xs text-gray-500">
                      Supports PDF and DOCX files up to 10MB
                    </div>
                  </>
                )}
              </div>
            </div>

            {/* Upload Progress */}
            {isUploading && (
              <div className="mt-4">
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm font-medium text-gray-900">Uploading...</span>
                  <span className="text-sm text-gray-500">{uploadProgress}%</span>
                </div>
                <div className="w-full bg-gray-200 rounded-full h-2">
                  <div
                    className="bg-primary-600 h-2 rounded-full transition-all duration-300"
                    style={{ width: `${uploadProgress}%` }}
                  ></div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Policy Details */}
        <div className="card">
          <div className="card-body">
            <h3 className="text-lg font-medium text-gray-900 mb-6">Policy Details</h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Title */}
              <div>
                <label htmlFor="title" className="block text-sm font-medium text-gray-700 mb-2">
                  Policy Title *
                </label>
                <input
                  {...register('title', { required: 'Policy title is required' })}
                  type="text"
                  className={`input ${errors.title ? 'border-danger-500' : ''}`}
                  placeholder="Enter policy title"
                />
                {errors.title && (
                  <p className="mt-1 text-sm text-danger-600">{errors.title.message}</p>
                )}
              </div>

              {/* Policy Number */}
              <div>
                <label htmlFor="policyNumber" className="block text-sm font-medium text-gray-700 mb-2">
                  Policy Number *
                </label>
                <input
                  {...register('policyNumber', { required: 'Policy number is required' })}
                  type="text"
                  className={`input ${errors.policyNumber ? 'border-danger-500' : ''}`}
                  placeholder="Enter policy number"
                />
                {errors.policyNumber && (
                  <p className="mt-1 text-sm text-danger-600">{errors.policyNumber.message}</p>
                )}
              </div>

              {/* Insurance Company */}
              <div>
                <label htmlFor="insuranceCompany" className="block text-sm font-medium text-gray-700 mb-2">
                  Insurance Company *
                </label>
                <input
                  {...register('insuranceCompany', { required: 'Insurance company is required' })}
                  type="text"
                  className={`input ${errors.insuranceCompany ? 'border-danger-500' : ''}`}
                  placeholder="Enter insurance company name"
                />
                {errors.insuranceCompany && (
                  <p className="mt-1 text-sm text-danger-600">{errors.insuranceCompany.message}</p>
                )}
              </div>

              {/* Policy Type */}
              <div>
                <label htmlFor="policyType" className="block text-sm font-medium text-gray-700 mb-2">
                  Policy Type *
                </label>
                <select
                  {...register('policyType', { required: 'Policy type is required' })}
                  className={`input ${errors.policyType ? 'border-danger-500' : ''}`}
                >
                  <option value="">Select policy type</option>
                  <option value="health">Health Insurance</option>
                  <option value="life">Life Insurance</option>
                  <option value="property">Property Insurance</option>
                  <option value="liability">Liability Insurance</option>
                  <option value="auto">Auto Insurance</option>
                  <option value="business">Business Insurance</option>
                  <option value="other">Other</option>
                </select>
                {errors.policyType && (
                  <p className="mt-1 text-sm text-danger-600">{errors.policyType.message}</p>
                )}
              </div>

              {/* Coverage Amount */}
              <div>
                <label htmlFor="coverageAmount" className="block text-sm font-medium text-gray-700 mb-2">
                  Coverage Amount
                </label>
                <input
                  {...register('coverageAmount')}
                  type="number"
                  step="0.01"
                  className="input"
                  placeholder="Enter coverage amount"
                />
              </div>

              {/* Premium */}
              <div>
                <label htmlFor="premium" className="block text-sm font-medium text-gray-700 mb-2">
                  Premium
                </label>
                <input
                  {...register('premium')}
                  type="number"
                  step="0.01"
                  className="input"
                  placeholder="Enter premium amount"
                />
              </div>

              {/* Start Date */}
              <div>
                <label htmlFor="startDate" className="block text-sm font-medium text-gray-700 mb-2">
                  Start Date *
                </label>
                <input
                  {...register('startDate', { required: 'Start date is required' })}
                  type="date"
                  className={`input ${errors.startDate ? 'border-danger-500' : ''}`}
                />
                {errors.startDate && (
                  <p className="mt-1 text-sm text-danger-600">{errors.startDate.message}</p>
                )}
              </div>

              {/* End Date */}
              <div>
                <label htmlFor="endDate" className="block text-sm font-medium text-gray-700 mb-2">
                  End Date *
                </label>
                <input
                  {...register('endDate', { 
                    required: 'End date is required',
                    validate: (value) => {
                      const startDate = watch('startDate');
                      return new Date(value) > new Date(startDate) || 'End date must be after start date';
                    }
                  })}
                  type="date"
                  className={`input ${errors.endDate ? 'border-danger-500' : ''}`}
                />
                {errors.endDate && (
                  <p className="mt-1 text-sm text-danger-600">{errors.endDate.message}</p>
                )}
              </div>

              {/* Department */}
              <div>
                <label htmlFor="department" className="block text-sm font-medium text-gray-700 mb-2">
                  Department *
                </label>
                <input
                  {...register('department', { required: 'Department is required' })}
                  type="text"
                  className={`input ${errors.department ? 'border-danger-500' : ''}`}
                  placeholder="Enter department"
                />
                {errors.department && (
                  <p className="mt-1 text-sm text-danger-600">{errors.department.message}</p>
                )}
              </div>

              {/* Company */}
              <div>
                <label htmlFor="company" className="block text-sm font-medium text-gray-700 mb-2">
                  Company *
                </label>
                <input
                  {...register('company', { required: 'Company is required' })}
                  type="text"
                  className={`input ${errors.company ? 'border-danger-500' : ''}`}
                  placeholder="Enter company name"
                />
                {errors.company && (
                  <p className="mt-1 text-sm text-danger-600">{errors.company.message}</p>
                )}
              </div>

              {/* Description */}
              <div className="md:col-span-2">
                <label htmlFor="description" className="block text-sm font-medium text-gray-700 mb-2">
                  Description
                </label>
                <textarea
                  {...register('description')}
                  rows={4}
                  className="input"
                  placeholder="Enter policy description (optional)"
                />
              </div>
            </div>
          </div>
        </div>

        {/* AI Processing Notice */}
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
          <div className="flex">
            <AlertCircle className="h-5 w-5 text-blue-400 mt-0.5 mr-3 flex-shrink-0" />
            <div className="text-sm text-blue-800">
              <p className="font-medium mb-1">AI Processing</p>
              <p>After upload, your policy will be automatically analyzed using AI to extract key information, identify risks, and generate insights. This process typically takes 30-60 seconds.</p>
            </div>
          </div>
        </div>

        {/* Submit Button */}
        <div className="flex justify-end space-x-4">
          <button
            type="button"
            onClick={() => navigate('/policies')}
            className="btn btn-secondary"
            disabled={isUploading}
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={isUploading || !selectedFile}
            className="btn btn-primary disabled:opacity-50"
          >
            {isUploading ? (
              <>
                <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                Processing...
              </>
            ) : (
              <>
                <Upload className="h-4 w-4 mr-2" />
                Upload & Analyze
              </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
};

export default UploadPolicy;
